using System.Collections.Generic;
using System.Xml;

public Dictionary<string, string> ParseXmlConfiguration(string xmlFilePath)
{
    Dictionary<string, string> settings = new Dictionary<string, string>();

    XmlDocument xmlDoc = new XmlDocument();
    xmlDoc.XmlResolver = new XmlUrlResolver();
    xmlDoc.Load(xmlFilePath);

    XmlNodeList settingNodes = xmlDoc.SelectNodes("/settings/setting");
    foreach (XmlNode settingNode in settingNodes)
    {
        string key = settingNode.SelectSingleNode("key").InnerText;
        string value = settingNode.SelectSingleNode("value").InnerText;
        settings.Add(key, value);
    }

    return settings;
}